35	// Runes and moonstones are "components" — a distinct pricing tier that shares
36	// one base premium (and, later, block/alike rules). Naming the shared value
37	// makes the equality intentional rather than a coincidence two entries happen
38	// to share.
39	const COMPONENT_BASE_PREMIUM = 25;
40	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
41	// A "building block" of exactly this many alike components is offered at a
42	// special block premium instead of the per-component price.
43	const COMPONENT_BLOCK_SIZE = 3;
44	const COMPONENT_BLOCK_PREMIUM = 60;
45	
46	const BASE_PREMIUMS: Record<string, number> = {
47	  sword: 100,
48	  amulet: 60,
49	  staff: 80,
50	  potion: 40,
51	  rune: COMPONENT_BASE_PREMIUM,
52	  moonstone: COMPONENT_BASE_PREMIUM,
53	};
54	const PROCESSING_FEE = 5;
55	
56	// Surcharges are expressed as integer percentages and applied as
57	// `amount * percent / 100`, keeping the maths in integers (avoids float errors
58	// such as `100 * 1.1 === 100.00000000000001`).
59	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
60	const CURSE_SURCHARGE_PERCENT = 50;
61	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
62	const HIGH_ENCHANTMENT_MIN_LEVEL = 5;
63	const LOYALTY_DISCOUNT_PERCENT = 20;
64	const LOYALTY_MIN_YEARS = 2;
65	const FOLLOWUP_CONTRACT_DISCOUNT_PERCENT = 15;
66	const FIRST_CONTRACT_INDEX = 0;
67	const DEDUCTIBLE = 100;
68	
69	const percentOf = (amount: number, percent: number): number =>
70	  (amount * percent) / 100;
71	
72	// A surcharge that applies only when a condition holds, expressed as a
73	// percentage of some base amount (and 0 otherwise).
74	const conditionalPercent = (
75	  applies: boolean,
76	  amount: number,
77	  percent: number,
78	): number => (applies ? percentOf(amount, percent) : 0);
79	
80	// The base premium for a given item type, with unknown types priced at 0.
81	// This is the single point that reads BASE_PREMIUMS, so both per-item and
82	// per-group pricing share one definition of "the base price of a type".
83	const basePremiumForType = (type: string): number => BASE_PREMIUMS[type] ?? 0;
84	
85	// A single item's base premium. Block pricing is a group-level concern handled
86	// separately in sumBasePremiums, so a plain per-type lookup suffices here.
87	const itemBasePremium = (item: Item): number => basePremiumForType(item.type);
88	
89	// Item-specific surcharges, each a percentage of the item's own base premium:
90	// a curse adds 50%, and a highly-enchanted item (level >= 5) adds 30%. They
91	// stack when both apply.
92	const itemSurcharge = (item: Item): number => {
93	  const base = itemBasePremium(item);
94	  const curse = conditionalPercent(
95	    item.cursed ?? false,
96	    base,
97	    CURSE_SURCHARGE_PERCENT,
98	  );
99	  const highEnchantment = conditionalPercent(
100	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_MIN_LEVEL,
101	    base,
102	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
103	  );
104	  return curse + highEnchantment;
105	};
106	
107	const sumItemSurcharges = (items: Item[]): number =>
108	  items.reduce((total, item) => total + itemSurcharge(item), 0);
109	
110	const countByType = (items: Item[]): Map<string, number> => {
111	  const counts = new Map<string, number>();
112	  for (const item of items) {
113	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
114	  }
115	  return counts;
116	};
117	
118	const componentGroupPremium = (count: number): number =>
119	  count === COMPONENT_BLOCK_SIZE
120	    ? COMPONENT_BLOCK_PREMIUM
121	    : count * COMPONENT_BASE_PREMIUM;
122	
123	const typeGroupPremium = (type: string, count: number): number =>
124	  COMPONENT_TYPES.has(type)
125	    ? componentGroupPremium(count)
126	    : count * basePremiumForType(type);
127	
128	const sumBasePremiums = (items: Item[]): number =>
129	  [...countByType(items)].reduce(
130	    (total, [type, count]) => total + typeGroupPremium(type, count),
131	    0,
132	  );
133	
134	// Policy-wide modifiers scale with the whole policy's base premium.
135	// First-insurance is a surcharge every new policy pays; the loyalty discount
136	// rewards customers at or past the loyalty threshold.
137	const firstInsuranceSurcharge = (policyBase: number): number =>
138	  percentOf(policyBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
139	
140	const loyaltyDiscount = (customer: Customer, policyBase: number): number =>
141	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS
142	    ? percentOf(policyBase, LOYALTY_DISCOUNT_PERCENT)
143	    : 0;
144	
145	// Every contract after the customer's first quote in the scenario is a
146	// follow-up contract and earns a discount.
147	const followUpDiscount = (quoteIndex: number, policyBase: number): number =>
148	  quoteIndex > FIRST_CONTRACT_INDEX
149	    ? percentOf(policyBase, FOLLOWUP_CONTRACT_DISCOUNT_PERCENT)
150	    : 0;
151	
152	// Net signed adjustment that policy-wide modifiers make to the policy base:
153	// the first-insurance surcharge adds, the loyalty and follow-up discounts
154	// subtract. Grouping them keeps the quote formula at "base + item surcharges
155	// + policy-wide adjustments + fee".
156	const policyAdjustments = (
157	  customer: Customer,
158	  quoteIndex: number,
159	  policyBase: number,
160	): number =>
161	  firstInsuranceSurcharge(policyBase) -
162	  loyaltyDiscount(customer, policyBase) -
163	  followUpDiscount(quoteIndex, policyBase);
164	
165	export const quote = (
166	  customer: Customer,
167	  step: QuoteStep,
168	  quoteIndex: number,
169	): QuoteResult => {
170	  const policyBase = sumBasePremiums(step.items);
171	  const premium = Math.ceil(
172	    policyBase +
173	      sumItemSurcharges(step.items) +
174	      policyAdjustments(customer, quoteIndex, policyBase) +
175	      PROCESSING_FEE,
176	  );
177	  return { premium };
178	};
179	
180	// Reimbursement for one damage before the deductible: standard claims are
181	// reimbursed in full.
182	const reimbursement = (damage: Damage): number => damage.amount;
183	
184	// Payout for one damage: the reimbursement minus the deductible, never below 0.
185	const damagePayout = (damage: Damage): number =>
186	  Math.max(0, reimbursement(damage) - DEDUCTIBLE);
187	
188	export const claim = (
189	  _policyItems: Item[],
190	  incident: Incident,
191	  remainingCap: number,
192	): ClaimResult => {
193	  const requested = incident.damages.reduce(
194	    (total, damage) => total + damagePayout(damage),
195	    0,
196	  );
197	  const payout = Math.floor(Math.min(requested, remainingCap));
198	  return { payout, remainingCap: remainingCap - payout };
199	};
